                    Link link = context.getObjectById(Link.class, value);

                    String psStatusString = "";
                    if(null!=link){
                    Identity identity = link.getIdentity();
                    if(null!=identity){

                    Application peopleSoftApp = context.getObjectByName(Application.class,"DB-Peoplesoft-HCM-Primary");
                    IdentityService idService = new IdentityService(context);
                    if(null!=peopleSoftApp && null!=idService){
                    List<Link> links = idService.getLinks(identity,peopleSoftApp);
                    if(null!=links){
                    for(Link link:links){
                    Object psStatus =  link.getAttribute("EMPL_STATUS");
                    if(null!=psStatus){
                    psStatusString = psStatus.toString();
                    }
                    }
                    links = null;
                    }
                    }

                    context.decache(identity);
                    if(null!=peopleSoftApp){
                    context.decache(peopleSoftApp);
                    }
                    }
                    }

                    if(Util.isNotNullOrEmpty(psStatusString)){
                    if(psStatusString.equalsIgnoreCase("A") || psStatusString.equalsIgnoreCase("L ") || psStatusString.equalsIgnoreCase("P") || psStatusString.equalsIgnoreCase("S")){
                    psStatusString = "A";
                    } else{
                    psStatusString = "I";
                    }
                    }

                    return psStatusString;

                    import sailpoint.object.Link;
                    import sailpoint.tools.Util;
                    import java.text.SimpleDateFormat;
                    import java.lang.Math;

                    Link link = context.getObjectById(Link.class, value);
                    String accountExpires = link.getAttribute("accountExpires");

                    if(Util.isNotNullOrEmpty(accountExpires)){
                    if(accountExpires.equalsIgnoreCase("never") || accountExpires.equalsIgnoreCase("0") || accountExpires.equalsIgnoreCase("9223372036854775807")){
                    return accountExpires;
                    }

                    SimpleDateFormat sdf = new SimpleDateFormat("MM/dd/yyyy HH:mm:ss a z");
                    Date cre = null;
                    try {
                    cre = sdf.parse(accountExpires);
                    } catch (ParseException e) {
                    return accountExpires;
                    }
                    sfd = new SimpleDateFormat("M/d/y H:m:s");
                    return sfd.format(cre);
                    }

                    return accountExpires;

                    import sailpoint.object.Link;
                    import sailpoint.tools.Util;
                    import java.text.SimpleDateFormat;
                    import java.lang.Math;

                    import sailpoint.object.Identity;
                    import sailpoint.object.Application;
                    import sailpoint.api.IdentityService;
                    import sailpoint.object.Attributes;
                    import sailpoint.api.SailPointContext;
                    import java.text.ParseException;

                    Link link = context.getObjectById(Link.class, value);
                    String lastLogonTimestamp = link.getAttribute("lastLogonTimestamp");
                    Date adLastLogonDate = null;
                    Date gSuiteLastLogonDate = null;
                    Date duoLastLogonDate = null;
                    SimpleDateFormat sfd = new SimpleDateFormat("M/d/y H:m:s");

                    if(Util.isNotNullOrEmpty(lastLogonTimestamp) && !lastLogonTimestamp.equals("0")){
                    long nanoseconds = Long.parseLong(lastLogonTimestamp);
                    long mills = (nanoseconds/10000000);
                    long unix = (((1970-1601) * 365) - 3 + Math.round((1970-1601)/4) ) * 86400L;
                    long timeStamp = mills - unix ;

                    Date date = new Date(timeStamp*1000L); // *1000 is to convert seconds to milliseconds
                    if(null!=date){
                    adLastLogonDate = date;
                    }
                    }

                    String gSuitelastLoginString = "";
                    String duoLastLoginString = "";
                    if(null!=link){
                    Identity identity = link.getIdentity();
                    if(null!=identity){

                    Application gsuite = context.getObjectByName(Application.class,"GSuite");
                    IdentityService idService = new IdentityService(context);
                    if(null!=gsuite && null!=idService){
                    List<Link> links = idService.getLinks(identity,gsuite);
                    if(null!=links){
                    for(Link link:links){
                    Object lastLogin =  link.getAttribute("lastLoginTime");
                    if(null!=lastLogin){
                    gSuitelastLoginString = lastLogin.toString();
                    }
                    }
                    links = null;
                    }
                    }

                    Application duo = context.getObjectByName(Application.class,"Duo");
                    IdentityService idService = new IdentityService(context);
                    if(null!=duo && null!=idService){
                    List<Link> links = idService.getLinks(identity,duo);
                    if(null!=links){
                    for(Link link:links){
                    Object lastLogin =  link.getAttribute("last_login");
                    if(null!=lastLogin){
                    duoLastLoginString = lastLogin.toString();
                    }
                    }
                    links = null;
                    }
                    }

                    context.decache(identity);
                    context.decache(gsuite);
                    context.decache(duo);
                    }
                    }

                    if(Util.isNotNullOrEmpty(gSuitelastLoginString)){
                    SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSS");
                    Date cre = null;
                    try {
                    cre = sdf.parse(gSuitelastLoginString);
                    } catch (ParseException e) {
                    //TODO
                    }
                    if(null!=cre){
                    gSuiteLastLogonDate = cre;
                    }
                    }

                    if(Util.isNotNullOrEmpty(duoLastLoginString)){
                    SimpleDateFormat sdf = new SimpleDateFormat("EEE MMM dd HH:mm:ss z yyyy");
                    Date cre = null;
                    try {
                    cre = sdf.parse(duoLastLoginString);
                    } catch (ParseException e) {
                    //TODO
                    }
                    if(null!=cre){
                    duoLastLogonDate = cre;
                    }
                    }

                    Date latest = null;

                    if(null!=adLastLogonDate && null!=gSuiteLastLogonDate && null!=duoLastLogonDate){
                    latest = Collections.max(Arrays.asList(adLastLogonDate, gSuiteLastLogonDate, duoLastLogonDate));
                    } else if(null!=adLastLogonDate && null!=gSuiteLastLogonDate){
                    latest = Collections.max(Arrays.asList(adLastLogonDate, gSuiteLastLogonDate));
                    } else if(null!=adLastLogonDate && null!=duoLastLogonDate){
                    latest = Collections.max(Arrays.asList(adLastLogonDate, duoLastLogonDate));
                    } else if(null!=gSuiteLastLogonDate && null!=duoLastLogonDate){
                    latest = Collections.max(Arrays.asList(gSuiteLastLogonDate, duoLastLogonDate));
                    } else if(null!=adLastLogonDate){
                    latest = adLastLogonDate;
                    } else if(null!=gSuiteLastLogonDate){
                    latest = gSuiteLastLogonDate;
                    } else if(null!=duoLastLogonDate){
                    latest = duoLastLogonDate;
                    }

                    if(null!=latest){
                    return sfd.format(latest);
                    }
                    else{
                    return "";
                    }

                    import sailpoint.object.Link;
