                    import sailpoint.object.Link;
                    import sailpoint.tools.Util;

                    Link link = context.getObjectById(Link.class, value);
                    String principalName = link.getAttribute("msDS-PrincipalName");

                    if(Util.isNotNullOrEmpty(principalName)){
                    principalName = principalName.replace("\\","\\\\");
                    String[] splitString = principalName.split("\\\\");
                    if(null!=splitString && splitString.length > 0){
                    return splitString[0];
                    }
                    }

                    return principalName;

                    import sailpoint.object.Link;
                    import sailpoint.tools.Util;

                    Link link = context.getObjectById(Link.class, value);
                    String dn = link.getNativeIdentity();
                    if(Util.isNotNullOrEmpty(dn)){
                    dn = dn.replaceAll("^.+?,(CN|OU.+)","$1");
                    dn = dn.replaceAll(",OU=","/");
                    dn = dn.replaceAll("OU=","");
                    dn = dn.replaceAll("CN=","");
                    dn = dn.replaceFirst(",DC=","/");
                    dn = dn.replaceAll(",DC=",".");
                    }
                    return dn;

